from dataclasses import dataclass
from typing import Any, Callable
from datetime import datetime


# ── Definición de herramienta ─────────────────────────────────────────────────

@dataclass
class ToolDef:
    nombre: str
    descripcion: str
    parametros: list[str]  # nombres de parámetros requeridos
    funcion: Callable


# ── Implementaciones de tools ─────────────────────────────────────────────────

# Base de datos simulada
_USUARIOS = {
    'USR-001': {'nombre': 'Ana García', 'email': 'ana@nave.ar', 'nivel': 'premium'},
    'USR-002': {'nombre': 'Carlos López', 'email': 'carlos@nave.ar', 'nivel': 'basic'},
}

_PEDIDOS = {
    'ORD-555': {'usuario_id': 'USR-001', 'monto': 12500, 'estado': 'entregado'},
    'ORD-556': {'usuario_id': 'USR-002', 'monto': 3200, 'estado': 'en_transito'},
}


def buscar_usuario(usuario_id: str) -> dict:
    usuario = _USUARIOS.get(usuario_id)
    if not usuario:
        raise ValueError(f'Usuario {usuario_id} no encontrado')
    return usuario


def consultar_pedido(pedido_id: str) -> dict:
    pedido = _PEDIDOS.get(pedido_id)
    if not pedido:
        raise ValueError(f'Pedido {pedido_id} no encontrado')
    return pedido


def calcular_reembolso(pedido_id: str, porcentaje: str) -> dict:
    pedido = _PEDIDOS.get(pedido_id)
    if not pedido:
        raise ValueError(f'Pedido {pedido_id} no encontrado')
    pct = float(porcentaje) / 100
    monto_reembolso = pedido['monto'] * pct
    return {
        'pedido_id': pedido_id,
        'monto_original': pedido['monto'],
        'porcentaje': porcentaje,
        'reembolso': round(monto_reembolso, 2),
    }


def escalar_ticket(usuario_id: str, motivo: str) -> dict:
    return {
        'ticket_id': f'TKT-{datetime.now().strftime("%H%M%S")}',
        'usuario_id': usuario_id,
        'motivo': motivo,
        'prioridad': 'alta',
        'asignado_a': 'equipo-soporte-l2',
    }


# ── Registro de tools ─────────────────────────────────────────────────────────

TOOL_REGISTRY: dict[str, ToolDef] = {
    'buscar_usuario': ToolDef(
        nombre='buscar_usuario',
        descripcion='Busca información de un usuario por su ID',
        parametros=['usuario_id'],
        funcion=buscar_usuario,
    ),
    'consultar_pedido': ToolDef(
        nombre='consultar_pedido',
        descripcion='Consulta el estado y detalles de un pedido',
        parametros=['pedido_id'],
        funcion=consultar_pedido,
    ),
    'calcular_reembolso': ToolDef(
        nombre='calcular_reembolso',
        descripcion='Calcula el monto de reembolso según porcentaje',
        parametros=['pedido_id', 'porcentaje'],
        funcion=calcular_reembolso,
    ),
    'escalar_ticket': ToolDef(
        nombre='escalar_ticket',
        descripcion='Escala el caso al equipo de soporte nivel 2',
        parametros=['usuario_id', 'motivo'],
        funcion=escalar_ticket,
    ),
}


# ── Executor con validación y logging ─────────────────────────────────────────

class ToolExecutor:
    def __init__(self, registry: dict[str, ToolDef]):
        self.registry = registry
        self.invocaciones: list[dict] = []

    def ejecutar(self, nombre: str, **kwargs) -> dict[str, Any]:
        if nombre not in self.registry:
            return {'ok': False, 'error': f'Tool "{nombre}" no existe en el registro'}

        tool = self.registry[nombre]

        # Validar parámetros requeridos
        faltantes = [p for p in tool.parametros if p not in kwargs]
        if faltantes:
            return {'ok': False, 'error': f'Parámetros faltantes: {faltantes}'}

        # Ejecutar y registrar
        inicio = datetime.now()
        try:
            resultado = tool.funcion(**kwargs)
            log = {'tool': nombre, 'kwargs': kwargs, 'ok': True, 'duracion_ms': (datetime.now() - inicio).microseconds // 1000}
            self.invocaciones.append(log)
            return {'ok': True, 'resultado': resultado}
        except Exception as e:
            log = {'tool': nombre, 'kwargs': kwargs, 'ok': False, 'error': str(e)}
            self.invocaciones.append(log)
            return {'ok': False, 'error': str(e)}

    def reporte(self):
        print(f'\n=== Reporte de invocaciones ({len(self.invocaciones)} total) ===')
        for inv in self.invocaciones:
            estado = '✓' if inv['ok'] else '✗'
            print(f'  {estado} {inv["tool"]}({inv["kwargs"]}) → {"ok" if inv["ok"] else inv["error"]}')


# ── Demo: flujo de soporte completo ──────────────────────────────────────────

if __name__ == '__main__':
    executor = ToolExecutor(TOOL_REGISTRY)

    print('=== Caso: cliente pide reembolso del 50% por pedido dañado ===')
    print()

    # 1. Verificar usuario
    r = executor.ejecutar('buscar_usuario', usuario_id='USR-001')
    print(f'1. Usuario: {r["resultado"]["nombre"]} ({r["resultado"]["nivel"]})')

    # 2. Consultar pedido
    r = executor.ejecutar('consultar_pedido', pedido_id='ORD-555')
    print(f'2. Pedido: ${r["resultado"]["monto"]} — {r["resultado"]["estado"]}')

    # 3. Calcular reembolso
    r = executor.ejecutar('calcular_reembolso', pedido_id='ORD-555', porcentaje='50')
    print(f'3. Reembolso: ${r["resultado"]["reembolso"]}')

    # 4. Escalar (monto > umbral)
    if r['resultado']['reembolso'] > 5000:
        r = executor.ejecutar('escalar_ticket', usuario_id='USR-001', motivo='Reembolso > $5000 requiere aprobación')
        print(f'4. Ticket escalado: {r["resultado"]["ticket_id"]}')

    # 5. Tool inexistente (demo de error)
    r = executor.ejecutar('enviar_email', usuario_id='USR-001')
    print(f'5. Error esperado: {r["error"]}')

    executor.reporte()
